CustomField.formula:
LEFT(
    SUBSTITUTE(
        SUBSTITUTE(
            SUBSTITUTE(
                Client__r.Name,
                "-", ""
            ),
            "&", ""
        ),
        " ", ""
    ),
    1
) & LEFT(
    SUBSTITUTE(
        SUBSTITUTE(
            SUBSTITUTE(
                RIGHT(Client__r.Name, LEN(Client__r.Name) - FIND(" ", Client__r.Name)),
                "-", ""
            ),
            "&", ""
        ),
        " ", ""
    ),
    1
)
